import { computed, inject, signal } from '@angular/core';
import { ComparisonToolService } from './comparison-tool.service';
export class ComparisonToolFilterService {
    comparisonToolService = inject(ComparisonToolService);
    DEFAULT_SIGNIFICANCE_THRESHOLD = 0.05;
    significanceThresholdSignal = signal(this.DEFAULT_SIGNIFICANCE_THRESHOLD);
    significanceThresholdActiveSignal = signal(false);
    significanceThreshold = this.significanceThresholdSignal.asReadonly();
    significanceThresholdActive = this.significanceThresholdActiveSignal.asReadonly();
    searchTerm = this.comparisonToolService.searchTerm;
    filters = this.comparisonToolService.filters;
    hasSelectedFilters = computed(() => {
        return this.filters().some((filter) => filter.options.some((option) => option.selected));
    });
    setFilters(filters) {
        // Use structuredClone to ensure a new reference is created
        const clonedFilters = structuredClone(filters);
        this.comparisonToolService.updateQuery({
            filters: clonedFilters,
            pageNumber: this.comparisonToolService.FIRST_PAGE_NUMBER,
        });
    }
    updateSearchTerm(term) {
        this.comparisonToolService.updateQuery({
            searchTerm: term,
            pageNumber: this.comparisonToolService.FIRST_PAGE_NUMBER,
        });
    }
    setSignificanceThresholdActive(value) {
        this.significanceThresholdActiveSignal.set(value);
    }
    setSignificanceThreshold(value) {
        this.significanceThresholdSignal.set(value);
    }
}
